// Production service worker — generated by dotnet publish alongside
// service-worker-assets.js which lists every Blazor WASM static asset
// with its content hash.
//
// Strategy:
//   • App shell (JS, CSS, WASM, icons, manifest) → Cache First
//   • API / hub calls (/auth, /hubs, /api) → Network Only (never cached)
//   • Navigation requests → serve from cache or show offline.html

const CACHE_NAME_PREFIX = 'familysplit';
const OFFLINE_URL        = 'offline.html';

let assetsManifest = { version: 'dev', assets: [] };
try {
    importScripts('service-worker-assets.js');
    assetsManifest = self.assetsManifest;
} catch { /* no-op outside of dotnet publish */ }

const CACHE_NAME = `${CACHE_NAME_PREFIX}-${assetsManifest.version}`;

// ── Install: precache all Blazor assets + offline fallback ────────────────────

self.addEventListener('install', event => {
    event.waitUntil(
        (async () => {
            const cache = await caches.open(CACHE_NAME);
            await cache.add(new Request(OFFLINE_URL, { cache: 'reload' }));

            const urls = assetsManifest.assets
                .filter(a => a.assetType !== 'pdb')
                .map(a => a.url);

            await cache.addAll(urls);
        })()
    );
    self.skipWaiting();
});

// ── Activate: remove stale caches ────────────────────────────────────────────

self.addEventListener('activate', event => {
    event.waitUntil(
        (async () => {
            const keys = await caches.keys();
            await Promise.all(
                keys
                    .filter(k => k.startsWith(CACHE_NAME_PREFIX) && k !== CACHE_NAME)
                    .map(k => caches.delete(k))
            );
            await clients.claim();
        })()
    );
});

// ── Push: show OS notification only when app is not visible ──────────────────
// When the app is open, SignalR delivers the message and shows a snackbar.
// Showing an OS popup on top would be redundant, so we suppress it here.

self.addEventListener('push', event => {
    event.waitUntil(handlePush(event));
});

async function handlePush(event) {
    const data    = event.data?.json() ?? {};
    const title   = data.title   ?? 'FamilySplit';
    const options = {
        body:    data.body   ?? data.message ?? '',
        icon:    data.icon   ?? '/icons/icon-192.png',
        badge:   data.badge  ?? '/icons/icon-192.png',
        tag:     data.tag    ?? 'familysplit-settlement',
        data:    { url: data.url ?? '/' },
        vibrate: [100, 50, 100],
        requireInteraction: false,
    };

    // Suppress OS notification if any app window is currently visible —
    // SignalR will have already shown a snackbar.
    const windowClients = await clients.matchAll({ type: 'window', includeUncontrolled: true });
    const appIsVisible  = windowClients.some(c => c.visibilityState === 'visible');
    if (appIsVisible) return;

    await self.registration.showNotification(title, options);
}

self.addEventListener('notificationclick', event => {
    event.notification.close();
    const url = event.notification.data?.url ?? '/';
    event.waitUntil(
        clients.matchAll({ type: 'window', includeUncontrolled: true }).then(list => {
            const existing = list.find(c => c.url === url && 'focus' in c);
            if (existing) return existing.focus();
            if (clients.openWindow) return clients.openWindow(url);
        })
    );
});

// ── Fetch: cache-first for static assets, network-only for API/hubs ──────────

self.addEventListener('fetch', event => {
    const { request } = event;
    const url = new URL(request.url);

    // Never intercept API, auth, or SignalR hub calls.
    if (
        url.pathname.startsWith('/auth/') ||
        url.pathname.startsWith('/hubs/') ||
        url.pathname.startsWith('/api/')  ||
        url.hostname !== self.location.hostname
    ) {
        return;
    }

    // Navigation → serve app shell or offline fallback.
    if (request.mode === 'navigate') {
        event.respondWith(
            (async () => {
                try {
                    return await fetch(request);
                } catch {
                    const cache = await caches.open(CACHE_NAME);
                    return (
                        await cache.match(request) ??
                        await cache.match('/') ??
                        await cache.match(OFFLINE_URL)
                    );
                }
            })()
        );
        return;
    }

    // Static assets → cache-first.
    event.respondWith(
        (async () => {
            const cached = await caches.match(request);
            if (cached) return cached;
            try {
                const response = await fetch(request);
                if (response.ok) {
                    const cache = await caches.open(CACHE_NAME);
                    cache.put(request, response.clone());
                }
                return response;
            } catch {
                return new Response('', { status: 503 });
            }
        })()
    );
});
